return [
  {
    json: {
      topic: 'Using n8n for article automation',
      keywords: ['n8n', 'automation', 'content operations'],
      audience: 'developers and operators',
      tone: 'practical',
      targetLength: 1200,
      source: 'manual-sample'
    }
  }
];

const input = $json.body ?? $json;
const keywordInput = input.keywords ?? input.keyword ?? [];
const keywords = Array.isArray(keywordInput)
  ? keywordInput
  : String(keywordInput)
      .split(',')
      .map((keyword) => keyword.trim())
      .filter(Boolean);

return [
  {
    json: {
      topic: input.topic || 'Untitled article topic',
      keywords,
      audience: input.audience || 'general readers',
      tone: input.tone || 'practical',
      targetLength: Number(input.targetLength || input.target_length || 1200),
      source: 'webhook'
    }
  }
];

const topic = $json.topic;
const keywords = Array.isArray($json.keywords) ? $json.keywords : [];
const audience = $json.audience;
const tone = $json.tone;
const targetLength = $json.targetLength;
const primaryKeyword = keywords[0] || topic;
const slug = topic
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .slice(0, 80) || 'article-draft';

const outline = [
  {
    heading: 'Problem and context',
    intent: `Explain why ${topic} matters to ${audience}.`
  },
  {
    heading: 'Recommended workflow',
    intent: 'Describe the repeatable process and decision points.'
  },
  {
    heading: 'Implementation notes',
    intent: 'List practical setup details, dependencies, and pitfalls.'
  },
  {
    heading: 'Next steps',
    intent: 'Give the reader concrete actions to take.'
  }
];

const generationPrompt = [
  `Write an article about: ${topic}`,
  `Audience: ${audience}`,
  `Tone: ${tone}`,
  `Target length: about ${targetLength} words`,
  `Primary keyword: ${primaryKeyword}`,
  `Supporting keywords: ${keywords.join(', ') || 'none'}`,
  'Use the outline below, keep the structure clear, and avoid unsupported claims.',
  JSON.stringify(outline, null, 2)
].join('\n\n');

return [
  {
    json: {
      title: topic,
      slug,
      metadata: {
        audience,
        tone,
        targetLength,
        primaryKeyword,
        keywords,
        source: $json.source
      },
      outline,
      generationPrompt,
      nextAutomationSteps: [
        'Send generationPrompt to an LLM node or HTTP Request node.',
        'Store the draft in a review queue before publishing.',
        'Publish only after an explicit approval step.'
      ]
    }
  }
];
